\[
\begin{gathered}
\mathbf{F}(s, t)=\langle X(s, t), Y(s, t), Z(s, t), W(s, t)\rangle \\
\phi_{1}(s,)=\frac{X(s, t)}{W(s, t}, \quad \phi_{2}(s, t)=\frac{Y(s, t)}{W(s, t}, \quad \phi_{3}(s, t)=\frac{Z(s, t)}{W(s, t}
\end{gathered}
\]

\[
N_{z}=\left|\begin{array}{ll}
\phi_{1_{s}} & \phi_{1_{t}}  \tag{3}\\
\phi_{2_{s}} & \phi_{2_{t}}
\end{array}\right|
\]

\[
\begin{aligned}
\phi_{1_{s}} & =\frac{\left(W X_{s}-W_{s} X\right)}{W^{2}} \\
\phi_{1_{t}} & =\frac{\left(W X_{t}-W_{t} X\right)}{W^{2}} \\
\phi_{2_{s}} & =\frac{\left(W Y_{s}-W_{s} Y\right)}{W^{2}} \\
\phi_{2_{t}} & =\frac{\left(W Y_{t}-W_{t} Y\right)}{W^{2}}
\end{aligned}
\]

\[
J(s, t)=\left|\begin{array}{ll}
\frac{\left(W X_{s}-W_{s} X\right)}{W^{2}} & \frac{\left(W X_{t}-W_{t} X\right)}{W^{2}}  \tag{6}\\
\frac{\left(W Y_{s}-W_{s} Y\right)}{W^{2}} & \frac{\left(W Y_{t}-W_{t} Y\right)}{W^{2}}
\end{array}\right|
\]

\[
V(\wp)=\left\{p_{i} \mid p_{i} \in \operatorname{int}(\wp), \exists p_{b} \in \partial \wp, M\left(p_{i}\right)=M\left(p_{b}\right)\right\}
\]

\[
\begin{aligned}
\frac{X(u)}{W(u)} & =\frac{X(v)}{W(v)} \\
\frac{Y(u)}{W(u)} & =\frac{Y(v)}{W(v)} .
\end{aligned}
\]

\[
\begin{gathered}
\frac{(X(u) W(v)-X(v) W(u))}{(u-v)}=0 \\
\frac{(Y(u) W(v)-Y(v) W(u))}{(u-v)}=0
\end{gathered}
\]

\[
\begin{gathered}
D(s, t)=0 \\
D(u, v)=0 \\
\frac{X(s, t)}{W(s, t)}=\frac{X(u, v)}{W(u, v)} \\
\frac{Y(s, t)}{W(s, t)}=\frac{Y(u, v)}{W(u, v)}
\end{gathered}
\]

\[
\begin{aligned}
E(u, v, s, t)= & D^{2}(s, t)+D^{2}(u, v)+ \\
& (X(s, t) W(u, v)-X(u, v) W(s, t))^{2}+ \\
& (Y(s, t) W(u, v)-Y(u, v) W(s, t))^{2}
\end{aligned}
\]

\[
\begin{gathered}
D(s, t)=0 \\
\frac{X(s, t)}{W(s, t)}=\frac{X_{f}(u)}{W_{f}(u)} \\
\frac{Y(s, t)}{W(s, t)}=\frac{Y_{f}(u)}{W_{f}(u)}
\end{gathered}
\]
